/**
 * SSH tunnel: forwards localhost:15432 -> g5j115bwrn8125ev6ap1tjrv:5432
 * (Twenty CRM Postgres, via Coolify server)
 * Run with: node tunnel_twenty_pg.js
 */
const { Client } = require('C:/Users/ahazan2/AppData/Local/Temp/sshtool/node_modules/ssh2');
const net = require('net');
const fs = require('fs');

const SSH_CONFIG = {
  host: '178.156.180.212',
  port: 22,
  username: 'root',
  privateKey: fs.readFileSync('C:/Users/ahazan2/.ssh/id_ed25519')
};

const LOCAL_PORT = 15432;
const REMOTE_HOST = 'g5j115bwrn8125ev6ap1tjrv';
const REMOTE_PORT = 5432;

function createTunnel(socket) {
  const conn = new Client();
  conn.on('ready', () => {
    conn.forwardOut('127.0.0.1', LOCAL_PORT, REMOTE_HOST, REMOTE_PORT, (err, stream) => {
      if (err) { console.error('forwardOut error:', err); socket.end(); conn.end(); return; }
      socket.pipe(stream).pipe(socket);
      socket.on('close', () => conn.end());
      stream.on('close', () => socket.end());
    });
  }).on('error', e => { console.error('SSH error:', e.message); socket.end(); })
    .connect(SSH_CONFIG);
}

const server = net.createServer(createTunnel);
server.listen(LOCAL_PORT, '127.0.0.1', () => {
  console.log(`SSH tunnel ready: localhost:${LOCAL_PORT} -> ${REMOTE_HOST}:${REMOTE_PORT} (via ${SSH_CONFIG.host})`);
});

process.on('SIGINT', () => { server.close(); process.exit(); });

