      const del = await apiCall('DELETE', `/repos/${repo}/contents/AI_CONTEXT.md`, {
        message: 'docs: remove pointer — full guide now in .ai/',
        sha: oldCheck.body.sha
      });
      console.log(del.status === 200 ? `  ✓ removed AI_CONTEXT.md` : `  ✗ could not remove AI_CONTEXT.md: ${del.status}`);
    }

    // Delete old root-level AI_INFRASTRUCTURE_GUIDE.md if it exists (albert-standards)
    const rootCheck = await apiCall('GET', `/repos/${repo}/contents/AI_INFRASTRUCTURE_GUIDE.md`);
    if (rootCheck.status === 200) {
      const del = await apiCall('DELETE', `/repos/${repo}/contents/AI_INFRASTRUCTURE_GUIDE.md`, {
        message: 'docs: moved to .ai/ folder',
        sha: rootCheck.body.sha
      });
      console.log(del.status === 200 ? `  ✓ removed root AI_INFRASTRUCTURE_GUIDE.md` : `  ✗ ${del.status}`);
    }
  }
}

main().catch(console.error);
